"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([["3616"],{2581(e,t,a){a.r(t),a.d(t,{metadata:()=>n,default:()=>l,frontMatter:()=>o,contentTitle:()=>i,toc:()=>h,assets:()=>c});var n=JSON.parse('{"id":"architecture/design-decisions","title":"Deliberate choices & non-goals","description":"When you put Act next to the canonical event-sourcing toolkits \u2014 Axon, Marten, MassTransit, NServiceBus, Temporal, EventStoreDB \u2014 three patterns those frameworks ship as named primitives are missing here. There is no compensation stack, no upcaster chain, no exactly-once projection checkpoint. Read quickly, those look like gaps. They are not. Each one is a place where Act made a different call on purpose, because the peer pattern smuggles transactional or imperative thinking into an immutable log, and the same outcome is reachable on machinery Act already has.","source":"@site/docs/architecture/design-decisions.md","sourceDirName":"architecture","slug":"/architecture/design-decisions","permalink":"/act-root/docs/architecture/design-decisions","draft":false,"unlisted":false,"editUrl":"https://github.com/rotorsoft/act-root/edit/master/docs/docs/architecture/design-decisions.md","tags":[],"version":"current","frontMatter":{"id":"design-decisions","title":"Deliberate choices & non-goals"},"sidebar":"docs","previous":{"title":"Event schema evolution","permalink":"/act-root/docs/architecture/event-schema-evolution"},"next":{"title":"Extension points","permalink":"/act-root/docs/architecture/extension-points"}}'),r=a(9984),s=a(1736);let o={id:"design-decisions",title:"Deliberate choices & non-goals"},i="Deliberate choices & non-goals",c={},h=[{value:"Compensation \u2014 forward recovery, not a rollback framework",id:"compensation--forward-recovery-not-a-rollback-framework",level:2},{value:"Schema evolution \u2014 versioned names for live reads, archiver transform for bulk rewrite",id:"schema-evolution--versioned-names-for-live-reads-archiver-transform-for-bulk-rewrite",level:2},{value:"Projections \u2014 idempotent by definition, watermark at-least-once",id:"projections--idempotent-by-definition-watermark-at-least-once",level:2},{value:"The one real gap \u2014 deferred messages and timers",id:"the-one-real-gap--deferred-messages-and-timers",level:2}];function d(e){let t={a:"a",code:"code",em:"em",h1:"h1",h2:"h2",header:"header",p:"p",pre:"pre",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",...(0,s.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(t.header,{children:(0,r.jsx)(t.h1,{id:"deliberate-choices--non-goals",children:"Deliberate choices & non-goals"})}),"\n",(0,r.jsx)(t.p,{children:"When you put Act next to the canonical event-sourcing toolkits \u2014 Axon, Marten, MassTransit, NServiceBus, Temporal, EventStoreDB \u2014 three patterns those frameworks ship as named primitives are missing here. There is no compensation stack, no upcaster chain, no exactly-once projection checkpoint. Read quickly, those look like gaps. They are not. Each one is a place where Act made a different call on purpose, because the peer pattern smuggles transactional or imperative thinking into an immutable log, and the same outcome is reachable on machinery Act already has."}),"\n",(0,r.jsx)(t.p,{children:"This page documents the three as choices. For each: the pattern peers ship, the call Act made, why, and how you reach the same outcome. There is also one pattern that genuinely is missing \u2014 deferred messages and timers \u2014 and it is tracked as a real gap, not relitigated here as a choice. Knowing which is which is the point of the page."}),"\n",(0,r.jsx)(t.h2,{id:"compensation--forward-recovery-not-a-rollback-framework",children:"Compensation \u2014 forward recovery, not a rollback framework"}),"\n",(0,r.jsx)(t.p,{children:"The peer pattern is a saga with an undo stack. MassTransit and NServiceBus ship a courier; Temporal ships SAGA helpers. You declare the forward steps of a workflow, and alongside each one a compensating step, and when step N fails the framework walks the stack backward \u2014 undo N-1, undo N-2, down to the start. The rollback is a first-class concept the framework owns."}),"\n",(0,r.jsxs)(t.p,{children:['Act has no such primitive, and that is deliberate. A rollback stack is imperative-transaction thinking wearing a distributed-systems costume. It treats a multi-step workflow as something that can be "unwound," as if the steps had not happened. But in an event-sourced system the steps ',(0,r.jsx)(t.em,{children:"did"}),' happen \u2014 each one is a fact already committed to the log. The honest model is not "undo step N" but "step N failed, so now emit the fact that compensates for it." That compensating fact is just another event, and reacting to it is just another reaction. There is nothing to add to the framework because the framework already does exactly this.']}),"\n",(0,r.jsxs)(t.p,{children:["So compensation on Act is forward recovery. When a step fails, you emit a compensating event, and a reaction on that event drives whatever cleanup the failure demands. Consider a reservation workflow: an order reserves inventory, then attempts payment. Payment fails. There is no stack to pop. The payment slice emits ",(0,r.jsx)(t.code,{children:"PaymentFailed"}),", and a reaction releases the reservation:"]}),"\n",(0,r.jsx)(t.pre,{children:(0,r.jsx)(t.code,{className:"language-ts",metastring:"no-check",children:'export const PaymentSlice = slice()\n  .withState(Order)\n  .withState(Reservation)\n\n  .on("PaymentFailed")\n  .do(async function release(event, _stream, app) {\n    // The triggering event is threaded as `reactingTo` automatically.\n    await app.do(\n      "ReleaseReservation",\n      {\n        stream: event.data.reservationId,\n        actor: { id: "saga", name: "payment compensation" },\n      },\n      { reason: "payment_failed" }\n    );\n  })\n  .build();\n'})}),"\n",(0,r.jsxs)(t.p,{children:[(0,r.jsx)(t.code,{children:"ReleaseReservation"})," runs through ",(0,r.jsx)(t.code,{children:"load \u2192 reduce \u2192 commit"})," like any action, and produces a ",(0,r.jsx)(t.code,{children:"ReservationReleased"})," event on the reservation stream. The log now reads, in order: reservation made, payment attempted, payment failed, reservation released. That is the audit trail of the compensation, captured as facts, with no separate rollback ledger to keep consistent with the events. If releasing the reservation should itself trigger more cleanup \u2014 notify the customer, return a coupon to the wallet \u2014 those are reactions on ",(0,r.jsx)(t.code,{children:"ReservationReleased"}),", and the recovery composes outward the same way it composed inward."]}),"\n",(0,r.jsxs)(t.p,{children:["The drain machinery gives this its failure semantics for free. The compensation reaction is an ordinary reaction, so it inherits leasing, retries, and backoff. If releasing the reservation hits a transient fault, the reaction retries on the next cycle from the same watermark; nothing is lost. If the failure is permanent \u2014 the reservation service returns a 4xx, or the reservation was already cancelled by some other path \u2014 the handler throws ",(0,r.jsx)(t.code,{children:"NonRetryableError"}),", and the drain finalizer blocks that one stream on the first attempt rather than burning the retry budget. The blocked stream is then visible to ",(0,r.jsx)(t.code,{children:"app.blocked_streams()"}),", and an operator resumes it with ",(0,r.jsx)(t.code,{children:"app.unblock(...)"})," once the underlying problem is fixed. The compensation does not silently vanish and it does not wedge the rest of the workflow; it parks, loudly, on the stream that could not complete. See ",(0,r.jsx)(t.a,{href:"/act-root/docs/concepts/error-handling#non-retryable-errors",children:"Error handling \xa7 Non-retryable errors"})," and the ",(0,r.jsx)(t.a,{href:"/act-root/docs/architecture/concurrency-model",children:"Concurrency model"})," for the lease and block lifecycle this rides on."]}),"\n",(0,r.jsx)(t.p,{children:"The one thing forward recovery does not give you is automatic ordering of the undo. A rollback stack guarantees the reverse order of the forward steps; forward recovery gives you whatever order your reactions fire in. In practice this is rarely a real constraint, because compensations are usually independent (release the inventory, refund the card, void the shipment \u2014 none depends on the others), and where there is a true dependency you model it as a chain of reactions, each waiting on the event the previous one emits. The ordering you need becomes explicit in the event graph instead of implicit in a framework's unwinding loop."}),"\n",(0,r.jsx)(t.h2,{id:"schema-evolution--versioned-names-for-live-reads-archiver-transform-for-bulk-rewrite",children:"Schema evolution \u2014 versioned names for live reads, archiver transform for bulk rewrite"}),"\n",(0,r.jsx)(t.p,{children:"The peer pattern is the upcaster chain. Axon and Marten let you register a function that transforms an old payload shape into the new one transparently at read time, so a reducer only ever sees the latest version of an event. Add a field, register an upcaster that supplies its default, and every historical event appears to have always had the field. The reducer stays blissfully unaware that version 1 ever existed."}),"\n",(0,r.jsx)(t.p,{children:"Act splits this into two mechanisms, and the split is the important part, because the two halves solve genuinely different problems and conflating them is how people get confused about what Act can do."}),"\n",(0,r.jsxs)(t.p,{children:["The first mechanism is ",(0,r.jsx)(t.strong,{children:"versioned event names"}),", and it solves the live-read problem. When a change is breaking \u2014 a rename, a type change, a narrowed constraint \u2014 you add a new event name with a ",(0,r.jsx)(t.code,{children:"_v<n>"})," suffix, keep the old name in the registry forever, and write an explicit reducer for each version. ",(0,r.jsx)(t.code,{children:"OrderPlaced"})," and ",(0,r.jsx)(t.code,{children:"OrderPlaced_v2"})," both live in ",(0,r.jsx)(t.code,{children:".emits({...})"}),"; both have a branch in ",(0,r.jsx)(t.code,{children:".patch({...})"}),"; new actions emit ",(0,r.jsx)(t.code,{children:"OrderPlaced_v2"})," while historical ",(0,r.jsx)(t.code,{children:"OrderPlaced"})," events still reduce through their own branch. This is what gives you correct state on the hot read path: an event committed years ago is read back exactly as it was written, and the reducer that handles its version knows precisely which shape it is looking at. The cost is explicit and local \u2014 reducers branch on version \u2014 and that cost is the feature. Nothing is transformed behind your back, type information survives end to end because each name carries its own Zod schema, and the ",(0,r.jsx)(t.code,{children:"_v<n>"})," convention does double duty as the deprecation signal that the build refuses to let you ignore. The full mechanics, including the build-time throw on emitting a deprecated version, are in ",(0,r.jsx)(t.a,{href:"/act-root/docs/architecture/event-schema-evolution",children:"Event schema evolution"}),"."]}),"\n",(0,r.jsxs)(t.p,{children:["The second mechanism is the ",(0,r.jsx)(t.strong,{children:"source-to-sink archiver"}),", ",(0,r.jsx)(t.code,{children:".archives(fn)"}),", and it solves the bulk-migration problem. When a stream closes, the archiver runs inside the close cycle's guard window, reads the stream's full history, and writes it wherever you send cold data \u2014 S3, a warehouse, a JSONL file, or a freshly rebuilt stream. Because the archiver is ordinary code holding the events in hand, it can transform them on the way out: read ",(0,r.jsx)(t.code,{children:"OrderPlaced"})," (v1 shape), write ",(0,r.jsx)(t.code,{children:"OrderPlaced_v2"})," (v2 shape), and the cold copy is uniform. That is a real A-to-B rewrite, and it is the right tool when you want the archived or rebuilt copy to carry only the new shape so a future rehydrator never has to know v1 existed."]}),"\n",(0,r.jsxs)(t.p,{children:["Here is the nuance to be honest about, because it is the one place the two mechanisms get mistaken for each other. The archiver transforms on the way ",(0,r.jsx)(t.em,{children:"out"})," \u2014 to cold storage, or into a rebuilt stream \u2014 not on the hot read path. It does ",(0,r.jsx)(t.strong,{children:"not"}),' give you "reducers only ever see the latest shape" for your live store. The events still in the hot table are still in their original versions, and the reducers reading them still branch by version. Only versioned-name branching solves live reads; only the archiver solves bulk rewrite into a new home. If you want the upcaster\'s "reducers see one shape" property for live data, the answer on Act is that you do not get it, on purpose \u2014 you get a v1 reducer and a v2 reducer, and the explicitness is the trade. If what you actually want is to retire v1 from a system that has since closed those streams, the archiver rewrites them as it ships them cold, and the rebuilt or archived copy is single-shape.']}),"\n",(0,r.jsxs)(t.table,{children:[(0,r.jsx)(t.thead,{children:(0,r.jsxs)(t.tr,{children:[(0,r.jsx)(t.th,{children:"You want\u2026"}),(0,r.jsx)(t.th,{children:"Mechanism"}),(0,r.jsx)(t.th,{children:"Where it acts"})]})}),(0,r.jsxs)(t.tbody,{children:[(0,r.jsxs)(t.tr,{children:[(0,r.jsx)(t.td,{children:"Correct state for historical events still in the live store"}),(0,r.jsxs)(t.td,{children:["Versioned event names (",(0,r.jsx)(t.code,{children:"Foo_v2"}),") + a reducer branch per version"]}),(0,r.jsxs)(t.td,{children:["Hot read path, on every ",(0,r.jsx)(t.code,{children:"load"})," / replay"]})]}),(0,r.jsxs)(t.tr,{children:[(0,r.jsx)(t.td,{children:"A single-shape copy of closed streams in cold storage or a rebuilt stream"}),(0,r.jsxs)(t.td,{children:["The ",(0,r.jsx)(t.code,{children:".archives(fn)"})," source-to-sink transform"]}),(0,r.jsx)(t.td,{children:"On the way out, inside the close-cycle guard"})]})]})]}),"\n",(0,r.jsxs)(t.p,{children:['Why not just adopt upcasting and skip the split? Because the upcaster\'s transparency is exactly what Act declines to give the hot path. Transforming a payload at read time means the state you compute no longer corresponds, field for field, to what was committed \u2014 a bug in an upcaster is silently absorbed into "current state," and the immutable log stops being a faithful record of what the reducers actually saw. The versioned-name path keeps read-time transformation out of the picture entirely; the archiver path does transform, but only on the way to a ',(0,r.jsx)(t.em,{children:"new"})," artifact, never by rewriting history in place. Neither one mutates a committed event where it lives. See ",(0,r.jsx)(t.a,{href:"/act-root/docs/architecture/event-schema-evolution",children:"Event schema evolution \xa7 What the alternatives look like"})," for the longer argument against read-time upcasting and in-place migration scripts."]}),"\n",(0,r.jsx)(t.h2,{id:"projections--idempotent-by-definition-watermark-at-least-once",children:"Projections \u2014 idempotent by definition, watermark at-least-once"}),"\n",(0,r.jsx)(t.p,{children:"The peer pattern is the atomic checkpoint. Marten and the transactional-outbox family commit the projection write and the position checkpoint in a single database transaction, so the read model is updated exactly once: either both the row and the watermark advance, or neither does, and a crash can never leave the projection ahead of or behind its recorded position."}),"\n",(0,r.jsxs)(t.p,{children:["Act does not do this, and the reason is structural. An atomic watermark-plus-write would have to enroll your external projection store into the orchestrator's transaction boundary. The watermark lives in the store's ",(0,r.jsx)(t.code,{children:"__streams__"})," rows; your projection might live in a different Postgres database, a different engine entirely, an Elasticsearch index, a Redis key, a file. Making the checkpoint atomic with the projection write means either every projection target must be the same transactional resource as the event store, or the orchestrator must run a distributed transaction across both. Both options drag exactly the coupling Act is built to avoid back into the drain pipeline. So Act makes the opposite call: the watermark is ",(0,r.jsx)(t.strong,{children:"at-least-once"}),", and projection handlers are required to be ",(0,r.jsx)(t.strong,{children:"idempotent"}),"."]}),"\n",(0,r.jsx)(t.p,{children:"The contract is therefore short and absolute. A projection handler may run more than once for the same event. Replays happen on retry after a transient fault, on a worker crash between the write and the ack, on a deliberate rebuild, and on two workers briefly racing the same stream. Every write a handler makes must be safe to apply twice and produce the same result. In practice that means keying the write by something stable from the event \u2014 the event id, the stream and version, the stream name for last-writer-wins state \u2014 and expressing it as an upsert rather than a read-modify-write:"}),"\n",(0,r.jsx)(t.pre,{children:(0,r.jsx)(t.code,{className:"language-ts",metastring:"no-check",children:'export const TicketProjection = projection("tickets")\n  .on({ TicketOpened })\n    .do(async function opened({ stream, data }) {\n      await db\n        .insert(tickets)\n        .values({ id: stream, status: "open", title: data.title })\n        .onConflictDoNothing();          // re-applying is a no-op\n    })\n  .on({ MessageAdded })\n    .do(async function messageAdded({ stream }) {\n      // in-SQL increment, never read-then-write \u2014 replay-safe and race-free\n      await db\n        .update(tickets)\n        .set({ messages: sql`${tickets.messages} + 1` })\n        .where(eq(tickets.id, stream));\n    })\n  .build();\n'})}),"\n",(0,r.jsxs)(t.p,{children:["The ",(0,r.jsx)(t.code,{children:".onConflictDoNothing()"})," makes the insert a no-op on replay. The trap is the counter: an increment that reads the current value and writes value-plus-one double-counts the first time a replay happens, so you push the arithmetic into SQL (",(0,r.jsx)(t.code,{children:"messages + 1"})," as an in-place update) where it is naturally atomic, or you make the increment idempotent by deriving it from event position rather than accumulating. For counters that must be exact under replay, key the increment on event id so a second application of the same event is rejected. The pattern, batched-replay variant, and the failure modes that bite people are walked end to end in ",(0,r.jsx)(t.a,{href:"/act-root/docs/guides/projections-to-database",children:"Wiring projections to a database"}),"."]}),"\n",(0,r.jsx)(t.p,{children:'What you get for accepting idempotency as a requirement is that projections stay completely decoupled from the drain. The orchestrator never needs to know what a projection target is or whether its write committed; it only advances the watermark when the handler returns without throwing, and if it crashed before recording that, the next cycle simply re-delivers and the idempotent handler absorbs the repeat. Recovery after a crash is "replay from the last durable watermark," which is a no-op wherever the work already landed and a real write wherever it did not. There is no torn state to reconcile, because the projection never claimed to be exactly-once in the first place. The decoupling is the whole point: an at-least-once watermark plus an idempotent handler is strictly simpler to operate than a distributed checkpoint, and it is the only shape that lets a projection target be anything at all rather than only a co-transactional database.'}),"\n",(0,r.jsx)(t.h2,{id:"the-one-real-gap--deferred-messages-and-timers",children:"The one real gap \u2014 deferred messages and timers"}),"\n",(0,r.jsx)(t.p,{children:'Three of the four "missing" patterns are the choices above. The fourth is a genuine gap, and it is worth naming so the choices are not read as excuses.'}),"\n",(0,r.jsxs)(t.p,{children:['Act has no scheduling, timeout, or deferred-message primitive. The classic pattern \u2014 "if no payment within thirty minutes, emit ',(0,r.jsx)(t.code,{children:"OrderExpired"}),'," "on the ninetieth day fire the retention sweep," a saga waiting on the ',(0,r.jsx)(t.em,{children:"absence"})," of an event \u2014 has no first-class support today. Peers all ship it (Axon's ",(0,r.jsx)(t.code,{children:"DeadlineManager"}),", NServiceBus and MassTransit saga timeouts, Temporal timers, EventStoreDB scheduled messages); Act's only time-driven mechanism right now is ",(0,r.jsx)(t.code,{children:".autocloses"}),", a single-purpose time-windowed sweep. This is not a deliberate non-goal the way the three above are. It is missing, the design stance for closing it is settled (model the schedule as event-sourcing-native data, fire it from the drain's existing due-time machinery, add no cron dependency), and it is tracked at ",(0,r.jsx)(t.a,{href:"https://github.com/Rotorsoft/act-root/issues/1049",children:"#1049"}),". When you reach for a timer and find nothing, that is the gap \u2014 not another choice."]})]})}function l(e={}){let{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,r.jsx)(t,{...e,children:(0,r.jsx)(d,{...e})}):d(e)}},1736(e,t,a){a.d(t,{R:()=>o,x:()=>i});var n=a(5052);let r={},s=n.createContext(r);function o(e){let t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function i(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:o(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);